const fs = require('fs');
const path = String.raw`C:\Users\ai\.claude\projects\D--demo1-openmnemo\6dd44a8a-71b3-484d-912c-45d0b51e38d2\subagents\agent-a9b67be85bcdd332b.jsonl`;
const text = fs.readFileSync(path, 'utf8');
const patterns = [
  ['Anthropic', /sk-ant-[A-Za-z0-9_-]{10,}/g],
  ['OpenAI', /sk-[A-Za-z0-9_-]{10,}/g],
  ['GitHub', /gh[pousr]_[A-Za-z0-9_]{10,}/g],
  ['Slack', /xox[baprs]-[A-Za-z0-9-]{10,}/g],
  ['AWS', /AKIA[0-9A-Z]{16}/g],
  ['NPM', /npm_[A-Za-z0-9]{10,}/g],
  ['GenericLabel', /(?:api[_ -]?key|token|secret|password)\s*[:=]\s*[^\s"']{6,}/gi],
];
const lines = text.split(/\r?\n/);
let shown = 0;
for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  const hits = [];
  for (const [name, rx] of patterns) {
    if (rx.test(line)) hits.push(name);
    rx.lastIndex = 0;
  }
  if (!hits.length) continue;
  let redacted = line
    .replace(/sk-ant-[A-Za-z0-9_-]{10,}/g, 'sk-ant-[redacted]')
    .replace(/sk-[A-Za-z0-9_-]{10,}/g, 'sk-[redacted]')
    .replace(/gh[pousr]_[A-Za-z0-9_]{10,}/g, 'gh_[redacted]')
    .replace(/xox[baprs]-[A-Za-z0-9-]{10,}/g, 'xox-[redacted]')
    .replace(/AKIA[0-9A-Z]{16}/g, 'AKIA[redacted]')
    .replace(/npm_[A-Za-z0-9]{10,}/g, 'npm_[redacted]')
    .replace(/(api[_ -]?key|token|secret|password)\s*[:=]\s*[^\s"']{6,}/gi, (_, k) => `${k}=[redacted]`);
  console.log(`${i + 1}\t${hits.join('|')}\t${redacted.slice(0, 240)}`);
  shown += 1;
  if (shown >= 20) break;
}
console.log(`FOUND=${shown}`);
'@ | node -

