  88:       updated.push({
  89:         ...alert,
  90:         timestamp: now,
  91:         message,
  92:         count: (alert.count ?? 1) + 1,
  93:       })
  94:       found = true
  95:     } else {
  96:       updated.push({ ...alert })
  97:     }
  98:   }
  99: 
 100:   if (!found) {
